#include<stdio.h>
#include<stdlib.h>

int cf(void const *a, void const *b)
{
	return (*(int*)a - *(int*)b);
}
int main()
{
	int n, m, c=1, x=0, y=0, s=0, r=0, i, h;

	scanf("%d %d", &n, &m);
	int a[m+1], b[m+1];

	for(i=0; i<m; i++)
	{
		scanf("%d", &a[i]);
	}
	qsort(a, m, 4, cf);

	if(n>m){ printf("0");
	}
	else if(n==m){ printf("1");
	}
	else{
	for(i=0; i<m-1; i++)
	{
		if(a[i]==a[i+1])
		{
			c++;
			y=1;
		}
		else
		{
			b[r]=c;
			r++;
			c=1; y=0;
		}
	}
	if(y==1)
	{
		b[r]=c; r++;
	}
	qsort(b, r, 4, cf);

	for(i=1; i<=101; i++)
	{
		for(h=0; h<r; h++)
		{
			s+=b[h]/i;
		}
		if(s>=n)
		{
			x=i;
		}
		s=0;
	}
	printf("%d", x);
	}
	return 0;
}

