use std::io::{Read, stdin};

fn main() {
    let mut buf = String::new();
    stdin().read_to_string(&mut buf).unwrap();
    let mut tok = buf.split_whitespace();
    let mut get = || tok.next().unwrap();
    macro_rules! get {
        ($t:ty) => (get().parse::<$t>().unwrap());
        () => (get!(usize));
    }

    let n = get!();
    let m = get!();
    let mut fs = vec![0; 101];
    for _ in 0..m {
        fs[get!()] += 1;
    }
    let fs: Vec<_> = fs
        .into_iter()
        .filter(|v| *v > 0)
        .collect();

    let mut ans = 0;
    for i in 1..101 {
        let mut c = 0;
        for &f in fs.iter() {
            c += f / i;
        }
        if c >= n {
            ans = i;
        }
    }
    println!("{}", ans);
}
